  border: 2px solid var(--link-border);
}

.profile__name {
  font-size: 1.25rem;
  font-weight: 600;
  margin-bottom: 0.25rem;
  color: var(--text-primary);
}

.profile__bio {
  font-size: 0.9rem;
  color: var(--text-muted);
}

.links {
  list-style: none;
  width: 100%;
  max-width: var(--page-max-width);
  display: flex;
  flex-direction: column;
  gap: 0.625rem;
}

.links__item {
  display: block;
