  border-radius: var(--link-radius);
  color: var(--accent-color);
  text-decoration: none;
  text-align: center;
  transition: background-color 0.15s ease, color 0.15s ease;
}

.links__anchor:hover,
.links__anchor:focus {
  background-color: var(--link-bg-hover);
  color: var(--accent-hover);
  outline: none;
}

