cd /app && node -e "
import { loadTheme, listThemes } from './src/themes/loader.js';

// Test listThemes
const themes = listThemes();
console.log('Available themes:', themes);
console.assert(themes.includes('minimal-dark'), 'minimal-dark should be listed');

// Test loadTheme
const css = loadTheme('minimal-dark');
console.assert(css.includes('--bg-color'), 'Should contain --bg-color');
console.assert(css.includes('--text-primary'), 'Should contain --text-primary');
console.assert(css.includes('--accent-color'), 'Should contain --accent-color');
console.assert(css.includes('--link-bg'), 'Should contain --link-bg');
console.assert(css.includes('--font-body'), 'Should contain --font-body');
console.assert(css.includes('--avatar-radius'), 'Should contain --avatar-radius');
console.assert(css.includes('--page-max-width'), 'Should contain --page-max-width');
console.assert(css.includes('--footer-opacity'), 'Should contain --footer-opacity');
console.log('All contract properties present ✓');

// Test error on missing theme
try {
  loadTheme('nonexistent');
  console.assert(false, 'Should have thrown');
} catch (e) {
  console.assert(e.message.includes('nonexistent'), 'Error mentions theme name');
  console.assert(e.message.includes('minimal-dark'), 'Error lists available themes');
  console.log('Missing theme error ✓');
}

// Test sanitisation (directory traversal)
try {
  loadTheme('../package');
  console.assert(false, 'Should have thrown');
} catch (e) {
  console.log('Directory traversal blocked ✓');
}

// Test empty string
try {
  loadTheme('');
  console.assert(false, 'Should have thrown');
} catch (e) {
  console.log('Empty string rejected ✓');
}

console.log('All tests passed ✓');
"

cd /app && node -e "
import { generatePage } from './src/generator.js';
const html = generatePage({
  name: 'Test',
  bio: 'Hello',
  theme: 'minimal-dark',
  links: [{ label: 'Example', url: 'https://example.com' }]
});
console.assert(html.includes('--bg-color'), 'Generated HTML uses new tokens');
console.assert(html.includes('--text-primary'), 'Has text-primary');
console.assert(!html.includes('color: #'), 'No hardcoded colors outside :root');
console.log('Generator integration ✓');
"
